/// <summary>
/// Period date for the export
/// </summary>
/// <param name = "_periodDate">periodDate</param>
/// <returns>periodDate</returns>
[DataMemberAttribute]
public TransDate parmPeriodDate(TransDate _periodDate = periodDate)
{
    periodDate = _periodDate ;
    return periodDate ;
}

/// <summary>
/// Legal entity for the export
/// </summary>
/// <param name = "_legalEntity">legalEntity</param>
/// <returns>legalEntity</returns>
[DataMemberAttribute]
public DataAreaId parmLegalEntity(DataAreaId _legalEntity = legalEntity)
{
    legalEntity = _legalEntity ;
    return legalEntity ;
}
